(function(w){"use strict";const ID="time-add";function mins(v){const m=/^(\d{1,2}):(\d{2})$/.exec(v||"");if(!m)return null;const h=Number(m[1]),n=Number(m[2]);return h>=0&&h<24&&n>=0&&n<60?h*60+n:null}function compute(x){const a=mins(x.time),add=Number(x.minutes);if(a===null||!Number.isInteger(add))return{error:"시간과 더할 분을 올바르게 입력해 주세요."};const total=a+add,dayOffset=Math.floor(total/1440),norm=((total%1440)+1440)%1440,h=Math.floor(norm/60),m=norm%60;return{time:String(h).padStart(2,'0')+':'+String(m).padStart(2,'0'),dayOffset}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>기준 시간</label><input class="hm-calc-input" type="time" value="09:00"></div><div class="hm-calc-field"><label>더하거나 뺄 분</label><input class="hm-calc-input" inputmode="numeric" placeholder="예: 90 또는 -30"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">시간 계산</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [time,minutes]=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({time:time.value,minutes:Number(minutes.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}const day=r.dayOffset===0?'같은 날':(r.dayOffset>0?`+${r.dayOffset}일`:`${r.dayOffset}일`);api.setMessage(msg,"");api.setResult(res,api.resultCard("계산된 시간",r.time,day));});}
w.HM_CALC.register(ID,{compute,render});})(window);
